# Valid values for constrained fields
VALID_ROLES = {"user", "moderator", "admin"}
VALID_ACCOUNT_STATUSES = {"active", "suspended"}
VALID_SUBSCRIPTION_TIERS = {"free", "pro", "enterprise"}
UPDATABLE_FIELDS = {"email", "username", "role", "account_status", "subscription_tier"}

# Role hierarchy for permission checks
ROLE_HIERARCHY = {"user": 0, "moderator": 1, "admin": 2}


def get_current_user():
    """
    Simulate extracting current user from auth context.
    In production, this would decode a JWT token or session cookie.
    For MVP, we use X-User-Id header to simulate authentication.
    """
    user_id = request.headers.get("X-User-Id")
    if not user_id or user_id not in users_db:
        return None
    return users_db[user_id]


def require_admin(f):
    """Decorator to ensure the current user is an admin."""
    @wraps(f)
    def decorated_function(*args, **kwargs):
        current_user = get_current_user()
        if current_user is None:
            return jsonify({
                "error": "Unauthorized",
                "message": "Authentication required. Provide X-User-Id header."
            }), 401

        if current_user["role"] != "admin":
            return jsonify({
                "error": "Forbidden",
                "message": "Admin privileges required to perform this action."
            }), 403

        if current_user["account_status"] != "active":
            return jsonify({
                "error": "Forbidden",
                "message": "Your account is suspended. Contact support."
            }), 403

        # Attach current_user to kwargs for the route handler
        kwargs["current_user"] = current_user
        return f(*args, **kwargs)
    return decorated_function


def validate_email(email):
    """Basic email validation."""
    if not isinstance(email, str):
        return False
    if len(email) > 254:
        return False
    parts = email.split("@")
    if len(parts) != 2:
        return False
    local, domain = parts
    if not local or not domain:
        return False
    if "." not in domain:
        return False
    if len(local) > 64:
        return False
    return True


def validate_username(username):
    """Validate username format."""
    if not isinstance(username, str):
        return False, "Username must be a string."
    if len(username) < 3 or len(username) > 30:
        return False, "Username must be between 3 and 30 characters."
    if not username.isalnum() and not all(c.isalnum() or c in ("_", "-") for c in username):
        return False, "Username can only contain alphanumeric characters, underscores, and hyphens."
    return True, ""


def check_username_unique(username, exclude_user_id=None):
    """Check if username is already taken by another user."""
    for uid, user in users_db.items():
        if user["username"].lower() == username.lower() and uid != exclude_user_id:
            return False
    return True


def check_email_unique(email, exclude_user_id=None):
    """Check if email is already taken by another user."""
    for uid, user in users_db.items():
        if user["email"].lower() == email.lower() and uid != exclude_user_id:
            return False
    return True


@app.route("/api/users/<user_id>", methods=["PUT"])
@require_admin
def update_user(user_id, current_user):
    """
    Update a user record. Only admins can access this endpoint.

    PUT /api/users/<user_id>

    Request Body (JSON) - all fields optional:
    {
        "email": "newemail@example.com",
        "username": "newusername",
        "role": "user" | "moderator" | "admin",
        "account_status": "active" | "suspended",
        "subscription_tier": "free" | "pro" | "enterprise"
    }

    Returns:
        200: Updated user object
        400: Validation errors
        403: Permission denied
        404: User not found
    """
    # Check if target user exists
    if user_id not in users_db:
        return jsonify({
            "error": "Not Found",
            "message": f"User with id '{user_id}' not found."
        }), 404

    target_user = users_db[user_id]

    # Parse request body
    if not request.is_json:
        return jsonify({
            "error": "Bad Request",
            "message": "Request body must be JSON."
        }), 400

    data = request.get_json()

    if not data:
        return jsonify({
            "error": "Bad Request",
            "message": "Request body cannot be empty."
        }), 400

    # Check for unknown fields
    unknown_fields = set(data.keys()) - UPDATABLE_FIELDS
    if unknown_fields:
        return jsonify({
            "error": "Bad Request",
            "message": f"Unknown or non-updatable fields: {', '.join(sorted(unknown_fields))}",
            "updatable_fields": sorted(UPDATABLE_FIELDS)
        }), 400

    # Prevent admins from demoting themselves (safety check)
    if user_id == current_user["id"]:
        if "role" in data and data["role"] != "admin":
            return jsonify({
                "error": "Forbidden",
                "message": "You cannot demote your own admin role. Another admin must do this."
            }), 403
        if "account_status" in data and data["account_status"] == "suspended":
            return jsonify({
                "error": "Forbidden",
                "message": "You cannot suspend your own account."
            }), 403

    # Validate each field
    errors = {}

    if "email" in data:
        email = data["email"]
        if not validate_email(email):
            errors["email"] = "Invalid email format."
        elif not check_email_unique(email, exclude_user_id=user_id):
            errors["email"] = "Email is already in use by another user."

    if "username" in data:
        username = data["username"]
        valid, msg = validate_username(username)
        if not valid:
            errors["username"] = msg
        elif not check_username_unique(username, exclude_user_id=user_id):
            errors["username"] = "Username is already taken."

    if "role" in data:
        role = data["role"]
        if role not in VALID_ROLES:
            errors["role"] = f"Invalid role. Must be one of: {', '.join(sorted(VALID_ROLES))}"

    if "account_status" in data:
        status = data["account_status"]
        if status not in VALID_ACCOUNT_STATUSES:
            errors["account_status"] = f"Invalid account status. Must be one of: {', '.join(sorted(VALID_ACCOUNT_STATUSES))}"

    if "subscription_tier" in data:
        tier = data["subscription_tier"]
        if tier not in VALID_SUBSCRIPTION_TIERS:
            errors["subscription_tier"] = f"Invalid subscription tier. Must be one of: {', '.join(sorted(VALID_SUBSCRIPTION_TIERS))}"

    if errors:
        return jsonify({
            "error": "Validation Error",
            "message": "One or more fields failed validation.",
            "details": errors
        }), 400

    # Apply updates
    changes = {}
    for field in UPDATABLE_FIELDS:
        if field in data:
            old_value = target_user[field]
            new_value = data[field]
            if old_value != new_value:
                changes[field] = {"old": old_value, "new": new_value}
                target_user[field] = new_value

    # Update timestamp if there were actual changes
    if changes:
        target_user["updated_at"] = datetime.utcnow().isoformat() + "Z"

    return jsonify({
        "message": "User updated successfully." if changes else "No changes were made.",
        "user": target_user,
        "changes": changes,
        "updated_by": current_user["id"]
    }), 200


@app.route("/api/users/<user_id>", methods=["GET"])
@require_admin
def get_user(user_id, current_user):
    """Get a single user by ID."""
    if user_id not in users_db:
        return jsonify({
            "error": "Not Found",
            "message": f"User with id '{user_id}' not found."
        }), 404

    return jsonify({
        "user": users_db[user_id]
    }), 200


@app.route("/api/users", methods=["GET"])
@require_admin
def list_users(current_user):
    """List all users. Supports optional filtering."""
    role_filter = request.args.get("role")
    status_filter = request.args.get("account_status")
    tier_filter = request.args.get("subscription_tier")

    results = list(users_db.values())

    if role_filter:
        if role_filter not in VALID_ROLES:
            return jsonify({
                "error": "Bad Request",
                "message": f"Invalid role filter. Must be one of: {', '.join(sorted(VALID_ROLES))}"
            }), 400
        results = [u for u in results if u["role"] == role_filter]

    if status_filter:
        if status_filter not in VALID_ACCOUNT_STATUSES:
            return jsonify({
                "error": "Bad Request",
                "message": f"Invalid status filter. Must be one of: {', '.join(sorted(VALID_ACCOUNT_STATUSES))}"
            }), 400
        results = [u for u in results if u["account_status"] == status_filter]

    if tier_filter:
        if tier_filter not in VALID_SUBSCRIPTION_TIERS:
            return jsonify({
                "error": "Bad Request",
                "message": f"Invalid tier filter. Must be one of: {', '.join(sorted(VALID_SUBSCRIPTION_TIERS))}"
            }), 400
        results = [u for u in results if u["subscription_tier"] == tier_filter]

    return jsonify({
        "users": results,
        "total": len(results)
    }), 200


